import scala.xml.XML
import scala.util.Try

final case class ConfigSetting(path: String, value: String)

final case class ConfigParseResult(settings: List[ConfigSetting], rawXml: String)

object ConfigXmlService {
  def parseConfigXml(xmlInput: String): Either[String, ConfigParseResult] = {
    if (xmlInput == null || xmlInput.trim.isEmpty) {
      Left("XML input is empty")
    } else {
      Try(XML.loadString(xmlInput)).toEither.left.map(_.getMessage).map { root =>
        val settings = extractSettings(root)
        ConfigParseResult(settings, xmlInput)
      }
    }
  }

  private def extractSettings(node: scala.xml.Node): List[ConfigSetting] = {
    def loop(current: scala.xml.Node, prefix: String): List[ConfigSetting] = {
      val currentPath = if (prefix.isEmpty) current.label else s"$prefix/${current.label}"

      val attrs = current.attributes.asAttrMap.toList.map { case (k, v) =>
        ConfigSetting(s"$currentPath/@$k", v)
      }

      val textValue =
        current.child.collect {
          case t: scala.xml.Text if t.text.trim.nonEmpty => t.text.trim
        }.mkString(" ").trim

      val textSetting =
        if (textValue.nonEmpty && current.child.forall(_.isInstanceOf[scala.xml.Text])) {
          List(ConfigSetting(currentPath, textValue))
        } else Nil

      val childSettings = current.child.collect {
        case e: scala.xml.Elem => loop(e, currentPath)
      }.flatten

      attrs ++ textSetting ++ childSettings
    }

    loop(node, "")
  }

  def extractSettingMap(xmlInput: String): Either[String, Map[String, String]] =
    parseConfigXml(xmlInput).map { result =>
      result.settings.groupMapReduce(_.path)(_.value)((a, b) => b)
    }
}

final class ConfigApiService {
  def handleConfigRequest(xmlBody: String): Either[String, Map[String, String]] =
    ConfigXmlService.extractSettingMap(xmlBody)
}

